ValidationRule.errorConditionFormula:
AND(
    NOT(ISBLANK( Freezing_Date_Text__c )),
    OR(
        NOT(REGEX(Freezing_Date_Text__c , "^[0-9]{4}-[0-9]{2}-[0-9]{2}$")),
        ISBLANK(
            DATE(
                VALUE(LEFT(Freezing_Date_Text__c ,4)),
                VALUE(MID(Freezing_Date_Text__c ,6,2)),
                VALUE(RIGHT(Freezing_Date_Text__c ,2))
            )
        )
    )
)
